// At the top of your api.js file, add:
const API_BASE_URL = process.env.REACT_APP_API_URL || 'http://localhost:5000/api';

export const uploadImage = async (formData) => {
  try {
    console.log('📤 Uploading to:', `${API_BASE_URL}/disease/predict`);
    
    const response = await fetch(`${API_BASE_URL}/disease/predict`, {
      method: 'POST',
      body: formData,
      // Don't set Content-Type header - browser will set it with boundary
    });
    
    console.log('📥 Response status:', response.status);
    
    if (!response.ok) {
      const errorText = await response.text();
      console.error('❌ Error response:', errorText);
      throw new Error(`HTTP error! status: ${response.status}`);
    }
    
    const data = await response.json();
    console.log('✅ Upload successful:', data);
    return data;
  } catch (error) {
    console.error('❌ Fetch error:', error);
    
    // More specific error messages
    if (error.message.includes('Failed to fetch')) {
      throw new Error('Cannot connect to server. Make sure backend is running on port 5000');
    } else if (error.message.includes('413')) {
      throw new Error('File too large. Maximum size is 16MB');
    } else {
      throw error;
    }
  }
};
